import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface ConnectedDevices {
  total: number;
  online: number;
  offline: number;
}

interface EnergyUsage {
  current: number;
  unit: string;
  trend: number[];
}

interface RoomTemperature {
  room: string;
  temp: number;
}

interface WidgetData {
  connectedDevices: ConnectedDevices;
  energyUsage: EnergyUsage;
  roomTemperatures: RoomTemperature[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const data = response.data as WidgetData;
  const meta = response.meta as MetaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#2C2C2C' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#BDBDBD' }}>
              Energy Usage
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: meta.primaryColor }}>
              {data.energyUsage.current} {data.energyUsage.unit}
            </Typography>
          </Box>

          <LineChart
            height={120}
            series={[
              {
                data: data.energyUsage.trend,
                color: meta.accentColor,
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: [0, 1, 2, 3, 4, 5, 6], hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />

          <Stack direction="row" spacing={3}>
            <Box>
              <Typography variant="caption" color="text.secondary">
                Online Devices
              </Typography>
              <Typography variant="body2" fontWeight={500}>
                {data.connectedDevices.online}/{data.connectedDevices.total}
              </Typography>
            </Box>
            <Box>
              <Typography variant="caption" color="text.secondary">
                Offline Devices
              </Typography>
              <Typography variant="body2" fontWeight={500}>
                {data.connectedDevices.offline}
              </Typography>
            </Box>
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
